<?php namespace App\Domains\Tourism\Services; class PackageService { public function create(array $data) { return \App\Domains\Tourism\Models\Package::create($data); } public function update($id, array $data) { $package = \App\Domains\Tourism\Models\Package::find($id); return $package ? $package->update($data) : false; } public function delete($id) { return \App\Domains\Tourism\Models\Package::destroy($id); } public function list($tenantId) { return \App\Domains\Tourism\Models\Package::where('tenant_id', $tenantId)->get(); } }
